import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

export default function Login() {
  const [activeTab,  setActiveTab]  = useState('Faculty');
  const [rollNumber, setRollNumber] = useState('');
  const [password,   setPassword]   = useState('');
  const [loading,    setLoading]    = useState(false);
  const { login } = useAuth();
  const navigate  = useNavigate();

  const roleRoutes = { admin: '/admin', hod: '/hod', faculty: '/faculty', student: '/student' };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!rollNumber.trim() || !password.trim()) {
      toast.error('Please enter roll number and password');
      return;
    }
    setLoading(true);
    try {
      // Send tabType to backend — backend will reject wrong role
      const tabType = activeTab === 'Student' ? 'student' : 'faculty';
      const user    = await login(rollNumber.trim(), password, tabType);

      toast.success(`Welcome, ${user.name}!`);
      navigate(roleRoutes[user.role] || '/');
    } catch (err) {
      // Show backend error message directly (includes tab mismatch message)
      toast.error(err.response?.data?.message || 'Login failed. Check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  const handleTabChange = (tab) => {
    setActiveTab(tab);
    setRollNumber('');
    setPassword('');
  };

  return (
    <div className="login-page">
      <div className="login-card">

        <div className="login-header">
          <div className="login-logo">V</div>
          <h1>VEMU Institute of Technology</h1>
          <p>Student Mid Marks System</p>
        </div>

        {/* Tabs */}
        <div className="login-tabs">
          <button
            className={`login-tab${activeTab === 'Faculty' ? ' active' : ''}`}
            onClick={() => handleTabChange('Faculty')}
          >
            Faculty
          </button>
          <button
            className={`login-tab${activeTab === 'Student' ? ' active' : ''}`}
            onClick={() => handleTabChange('Student')}
          >
            Student
          </button>
        </div>

        <div className="login-body">

          {/* Tab hint */}
          <div style={{
            background: activeTab === 'Student' ? '#fce7f3' : '#e0e7ff',
            border:     `1px solid ${activeTab === 'Student' ? '#fbcfe8' : '#c7d2fe'}`,
            borderRadius: 8, padding: '8px 12px',
            fontSize: 12, marginBottom: 16,
            color: activeTab === 'Student' ? '#9d174d' : '#3730a3'
          }}>
            {activeTab === 'Student'
              ? '👨‍🎓 Students only — login with your Roll Number'
              : '👩‍🏫 Faculty, HOD & Admin only — login with your Employee ID'}
          </div>

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">
                {activeTab === 'Student' ? 'Roll Number' : 'Employee / Roll Number'}
              </label>
              <input
                className="form-input"
                type="text"
                placeholder={
                  activeTab === 'Student'
                    ? 'Enter your roll number'
                    : 'Enter Staff ID / HOD ID / Admin ID'
                }
                value={rollNumber}
                onChange={e => setRollNumber(e.target.value)}
                autoFocus
                autoComplete="username"
              />
            </div>

            <div className="form-group">
              <label className="form-label">Password</label>
              <input
                className="form-input"
                type="password"
                placeholder="Enter password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                autoComplete="current-password"
              />
            </div>

            <button className="btn-login" type="submit" disabled={loading}>
              {loading ? '⏳ Signing In...' : 'Sign In'}
            </button>
          </form>

          <div className="login-hint">
            Default password for new accounts:<br />
            <strong>Your Roll Number</strong>
          </div>
        </div>

        <div className="login-footer">© 2024 VEMU Institute of Technology</div>
      </div>
    </div>
  );
}
